  ('heelevel3-988e0de1-moex-00160', 'heelevel3-988e0de1', 'heelevel3-988e0de1-moex-110-ac2adf20', 'sub-heelevel3-988e0de1-02', NULL, 'single_choice', '甲機關原辦有保險之機械設備一部，成本10萬元，已提列折舊7萬元，因不堪使用辦理報廢，並 支付拆除費用3千元，後續並以2千元出售，依政府會計準則公報及中央政府普通公務單位會計 制度之一致規定，下列敘述何者正確？', '["資產報廢發生時，應認列財產交易損失2萬7千元", "支付拆除報廢資產費用時，應認列財產交易損失3千元", "資產報廢發生時，應認列財產交易損失2萬9千元", "報廢資產出售時，應沖轉財產交易損失2千元"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:33:27+00:00", "source_pdf_sha1": "dcb3276a8393", "answer_pdf_sha1": "807ca00816e0", "source_family": "moex-gov-tw", "moex": {"exam_code": "110090", "c": "326", "s": "1109", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "政府會計", "year": "110", "exam_name": "110年公務人員高等考試三級考試暨普通考試", "original_question_number": 21, "answer_corrected": false, "flags": [], "civil_slug": "heelevel3", "civil_category": "財務審計"}'::jsonb, NULL),
