  ('heelevel3-988e0de1-moex-00162', 'heelevel3-988e0de1', 'heelevel3-988e0de1-moex-110-ac2adf20', 'sub-heelevel3-988e0de1-02', NULL, 'single_choice', '甲機關購置蒸餾設備一部，該設備定價120萬元，現金折扣10萬元，又甲機關支付運費3萬元 及安裝費2萬元，另運輸途中因碰撞破損，甲機關支付修繕費1萬元，依政府會計準則公報規定， 甲機關應認列之設備成本為何？', '["110萬元", "115萬元", "116萬元", "125萬元"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:33:27+00:00", "source_pdf_sha1": "dcb3276a8393", "answer_pdf_sha1": "807ca00816e0", "source_family": "moex-gov-tw", "moex": {"exam_code": "110090", "c": "326", "s": "1109", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "政府會計", "year": "110", "exam_name": "110年公務人員高等考試三級考試暨普通考試", "original_question_number": 23, "answer_corrected": false, "flags": [], "civil_slug": "heelevel3", "civil_category": "財務審計"}'::jsonb, NULL),
